const TELEGRAM_MAX_LENGTH = 3900;
const truncateMessage = (value, max = TELEGRAM_MAX_LENGTH) => {
  const text = String(value || '').trim();
  if (text.length <= max) {
    return text;
  }
  return `${text.slice(0, Math.max(max - 37, 0)).trimEnd()}\n\n...resumo cortado para caber no Telegram.`;
};

const payload = (() => {
  try {
    return JSON.parse(String(items[0]?.json?.stdout ?? '{}'));
  } catch {
    return {};
  }
})();

const toNumber = (value, digits = 2) => {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed.toFixed(digits) : 'n/d';
};
const formatLoad = (value) => Array.isArray(value) && value.length === 3 ? value.join(' | ') : 'n/d';
const formatTop = (value) => Array.isArray(value) && value.length > 0
  ? value.map((entry) => `${entry.command} pid=${entry.pid} cpu=${entry.cpu_pct}% mem=${entry.mem_pct}%`).join('; ')
  : 'n/d';

const messageLines = [
  'Resumo VPS FeConect',
  '',
  `Status da VPS: ${String(payload.vps_status ?? 'OFF').toUpperCase()}`,
  `- checado em: ${payload.checked_at ?? 'n/d'}`,
  `- uptime: ${payload.uptime_human ?? 'n/d'}`,
  `- load average: ${formatLoad(payload.load_avg)}`,
  '',
  'Capacidade atual:',
  `- CPU: ${toNumber(payload.cpu_usage_pct)}% em ${payload.cpu_cores ?? 'n/d'} cores`,
  `- RAM: ${toNumber(payload.ram_used_gb)} GB / ${toNumber(payload.ram_total_gb)} GB (${toNumber(payload.ram_usage_pct)}%)`,
  `- Swap: ${toNumber(payload.swap_used_gb)} GB / ${toNumber(payload.swap_total_gb)} GB (${toNumber(payload.swap_usage_pct)}%)`,
  `- Disco /: ${toNumber(payload.disk_used_gb)} GB / ${toNumber(payload.disk_total_gb)} GB (${toNumber(payload.disk_usage_pct)}%)`,
  `- Disco livre /: ${toNumber(payload.disk_free_gb)} GB | inodes usados: ${payload.inode_usage_pct ?? 'n/d'}`,
  '',
  'Containers e processos:',
  `- containers Docker em execucao: ${payload.docker_running_containers ?? 0}`,
  `- containers reiniciando: ${payload.docker_restart_count ?? 0}`,
  `- top processos por CPU: ${formatTop(payload.top_processes)}`,
];

if (payload.meta_error) {
  messageLines.push('', `- observacao: coleta parcial (${payload.meta_error})`);
}

return [{
  json: {
    message: truncateMessage(messageLines.join('\n')),
    summary: payload,
  },
}];
